"후르가다":{en:{description:"Hurghada is Egypt's Red Sea resort city with world-class diving, coral reefs, and year-round sunshine.",spots:{"기프툰 섬":{"name":null,"desc":"Pristine island with crystal-clear snorkeling waters and stunning coral reefs in the Red Sea."},"사막 사파리":{"name":null,"desc":"Quad bike and dune buggy adventures in the Eastern Desert with Bedouin camp dinner."}}}},
"샤름엘셰이크":{en:{description:"Sharm El Sheikh is Egypt's premier Red Sea diving destination at the southern tip of the Sinai Peninsula.",spots:{"라스 모하메드":{"name":null,"desc":"Egypt's first national park with spectacular coral walls, shipwrecks, and abundant marine life."},"나마 베이":{"name":null,"desc":"Sharm's main tourist bay with restaurants, shops, and easy beach access to coral reefs."}}}},
