"그라츠":{en:{description:"Graz is Austria's second city, a UNESCO creative city with a well-preserved old town and cutting-edge contemporary architecture.",spots:{"쿤스트하우스":{"name":null,"desc":"Futuristic blue blob-shaped art museum that contrasts dramatically with the medieval rooftops around it."},"슐로스베르크":{"name":null,"desc":"Hilltop park with the iconic clock tower, reached by glass elevator or 260-step staircase."}}}},
"취리히":{en:{description:"Zurich is Switzerland's largest city — a pristine lakeside metropolis of banking, culture, chocolate, and Alpine views.",spots:{"취리히 호수":{"name":null,"desc":"Crystal-clear lake in the city center with swimming spots, boat cruises, and mountain panoramas."},"반호프 거리":{"name":null,"desc":"One of the world's most exclusive shopping streets, running from the train station to the lake."},"그로스뮌스터":{"name":null,"desc":"Romanesque cathedral with twin towers. Climb for panoramic views of Zurich and the Alps."}}}},
