"산세바스티안":{en:{description:"San Sebastián is Spain's Basque culinary capital — a stunning crescent beach, pintxos bars, and more Michelin stars per capita than almost anywhere.",spots:{"라콘차 해변":{"name":null,"desc":"One of Europe's best urban beaches, a perfect crescent of golden sand in an elegant bay."},"올드타운 핀초스":{"name":null,"desc":"The world's greatest bar-crawl — dozens of pintxos bars serving miniature culinary masterpieces."}}}},
"대전":{en:{description:"Daejeon is South Korea's science and technology hub, home to KAIST, the Expo Science Park, and Yuseong hot springs.",spots:{"국립중앙과학관":{"name":"National Science Museum","desc":"Korea's flagship science museum covering natural history, technology, and future innovation, with an astronomical observatory."},"한밭수목원":{"name":"Hanbat Arboretum","desc":"Korea's largest urban artificial arboretum, stretching across both sides of Expo Park with seasonal landscapes."},"유성온천":{"name":"Yuseong Hot Springs","desc":"Thousand-year-old alkaline hot springs area with free public foot baths throughout the district."},"성심당":{"name":"Sungsimdang","desc":"Legendary bakery founded in 1956, famous nationwide for its fried soboro bread and chive buns."},"대전 엑스포과학공원":{"name":"Daejeon Expo Park","desc":"Site of the 1993 Daejeon Expo, with the iconic Hanbit Tower as Daejeon's symbolic landmark."}}}},
"울산":{en:{description:"Ulsan is South Korea's largest industrial city, with whaling heritage, the Taehwa River, and the Yeongnam Alps mountain range.",spots:{"태화강 국가정원":{"name":"Taehwagang National Garden","desc":"Korea's 2nd national garden, featuring a 10-ri bamboo forest and seasonal flower fields along the Taehwa River."},"장생포 고래문화마을":{"name":"Jangsaengpo Whale Culture Village","desc":"Recreated historic whaling village featuring Korea's only whale museum and whale ecology experience hall."},"간절곶":{"name":"Ganjeolgot Cape","desc":"The spot on mainland Korea where the sun rises first, famed for its lighthouse and wish mailbox."},"영남알프스":{"name":"Yeongnam Alps","desc":"Nine 1,000m+ peaks including Gajisan and Sinbulsan, forming southern Korea's largest alpine massif."},"대왕암공원":{"name":"Daewangam Park","desc":"Dramatic coastal cliffs steeped in the legend of Silla's Queen, with crashing waves and ancient pine forest."}}}},
"포항":{en:{description:"Pohang is the city of POSCO Steel, famed for Homigot sunrise, Yeongildae Beach, and sashimi from Jukdo Market on Korea's east coast.",spots:{"호미곶":{"name":"Homigot Cape","desc":"Korea's easternmost mainland point, famous for the 'Hand of Harmony' sculpture and New Year sunrise festivals."},"영일대해수욕장":{"name":"Yeongildae Beach","desc":"Pohang's iconic beach featuring Korea's first offshore pavilion, spectacular at night."},"죽도시장":{"name":"Jukdo Market","desc":"East coast's largest traditional market where you can taste fresh sashimi, snow crab, and gwamegi."},"내연산 12폭포":{"name":"Naeyeonsan 12 Falls","desc":"Trekking route along a valley behind Bogyeongsa temple, passing twelve cascades with Sangsaeng and Gwaneum as highlights."},"구룡포 일본인 가옥거리":{"name":"Guryongpo Japanese Street","desc":"Historic street from Japanese colonial era fishing migrants, featured in the hit K-drama 'When the Camellia Blooms'."}}}},
"창원":{en:{description:"Changwon is the capital of South Gyeongsang Province, a planned city encompassing Masan and Jinhae, famous for cherry blossoms and spicy monkfish stew.",spots:{"진해 여좌천":{"name":"Yeojwacheon Stream","desc":"Korea's top cherry blossom spot — a 1.5km tunnel of blossoms forms during the Jinhae Gunhangje festival."},"경화역 공원":{"name":"Gyeonghwa Station Park","desc":"Famous photo spot with 800m of cherry trees lining an abandoned railway — the track-side cherry blossoms are iconic."},"용지호수공원":{"name":"Yongji Lake Park","desc":"Changwon citizens' favorite leisure spot featuring a musical fountain show and scenic night walks."},"마산 아구찜거리":{"name":"Masan Agujjim Street","desc":"Korea's only original monkfish-stew alley, serving the spicy and chewy Masan-style braised monkfish."},"돝섬 해상유원지":{"name":"Dotseom Maritime Park","desc":"Small island in Masan Bay converted into an amusement park, offering yachting and sunset views."}}}},
"안동":{en:{description:"Andong is the spiritual capital of Korea, home to the UNESCO Hahoe Folk Village, Dosan Seowon Confucian academy, and famed for jjimdak braised chicken.",spots:{"하회마을":{"name":"Hahoe Folk Village","desc":"UNESCO World Heritage village of the Pungsan Ryu clan, encircled by a bend of the Nakdong River."},"도산서원":{"name":"Dosan Seowon","desc":"UNESCO World Heritage Confucian academy where Joseon scholar Toegye Yi Hwang taught his disciples."},"월영교":{"name":"Woryeonggyo Bridge","desc":"Korea's longest wooden footbridge over Andong Lake, spectacular when illuminated at night."},"안동 구시장 찜닭골목":{"name":"Andong Jjimdak Alley","desc":"The birthplace of jjimdak braised chicken, with about 30 specialty restaurants clustered together."},"부용대":{"name":"Buyongdae Cliff","desc":"Cliff-top viewpoint offering sweeping views of Hahoe Village and the Nakdong River below."}}}},
