"공주":{en:{description:"Gongju was the second capital of the Baekje kingdom (475-538 CE), home to UNESCO World Heritage sites including Gongsanseong Fortress and King Muryeong's Tomb.",spots:{"공산성":{"name":"Gongsanseong Fortress","desc":"UNESCO World Heritage fortress that guarded the Baekje royal palace in Ungjin, with 2.66km of walls overlooking the Geum River."},"무령왕릉과 왕릉원":{"name":"Tomb of King Muryeong","desc":"1971 discovery of the brick tomb of Baekje's King Muryeong and his queen, yielding over 4,600 artifacts — Korea's greatest archaeological find."},"국립공주박물관":{"name":"Gongju National Museum","desc":"Showcases over 1,000 artifacts from King Muryeong's tomb, highlighting the Ungjin Baekje cultural legacy."},"마곡사":{"name":"Magoksa Temple","desc":"Thousand-year-old temple founded in 640 CE, part of UNESCO's 'Sansa, Buddhist Mountain Monasteries of Korea'."},"공주 산성시장":{"name":"Gongju Sanseong Market","desc":"Traditional market below Gongsanseong, famous for Gongju chestnut makgeolli, gukbap rice soup, and chestnut buns."}}}},
"요코하마":{en:{description:"Yokohama is Japan's second-largest city, an international port since 1859 famed for Chinatown, Minato Mirai night skyline, and the Girl in Red Shoes legend.",spots:{"미나토미라이 21":{"name":"Minato Mirai 21","desc":"Futuristic waterfront district featuring Yokohama Landmark Tower and the Cosmo World Ferris wheel."},"차이나타운":{"name":"Yokohama Chinatown","desc":"Japan's largest Chinatown with 600+ Chinese restaurants famous for dim sum and nikuman buns."},"산케이엔 정원":{"name":"Sankeien Garden","desc":"Traditional Japanese garden with 17 historic structures, stunning with cherry blossoms and autumn colors."},"컵누들 박물관":{"name":"Cup Noodles Museum","desc":"Interactive museum by Nissin founder where visitors can design their own original Cup Noodle."}}}},
"닛코":{en:{description:"Nikko is a UNESCO World Heritage city 2 hours from Tokyo, renowned for Tokugawa Ieyasu's Toshogu Shrine and dramatic waterfalls.",spots:{"닛코 도쇼구":{"name":"Nikko Toshogu Shrine","desc":"UNESCO World Heritage shrine dedicated to Tokugawa Ieyasu, famed for the 'See No Evil, Speak No Evil, Hear No Evil' three monkeys carving."},"케곤 폭포":{"name":"Kegon Falls","desc":"97m-tall waterfall, one of Japan's top three, with an elevator down to the base observation deck."},"주젠지 호수":{"name":"Lake Chuzenji","desc":"Alpine lake at 1,269m elevation with seasonal scenery — autumn foliage is legendary."},"신쿄 다리":{"name":"Shinkyo Bridge","desc":"Vermillion lacquered arched wooden bridge, one of Japan's three finest bridges and Nikko's icon."}}}},
"가마쿠라":{en:{description:"Kamakura is the ancient samurai capital just 1 hour from Tokyo, blending a Great Buddha, historic temples, and Shonan beaches into Kanto's premier day trip.",spots:{"가마쿠라 대불":{"name":"Great Buddha of Kamakura","desc":"13.35m bronze Amida Buddha statue at Kotoku-in Temple, cast in 1252 and designated a National Treasure."},"쓰루가오카 하치만구":{"name":"Tsurugaoka Hachimangu Shrine","desc":"The guardian shrine of the Kamakura shogunate, spectacular with cherry blossoms and lotus flowers."},"하세데라":{"name":"Hasedera Temple","desc":"Famous for its 9.18m eleven-headed Kannon statue and hydrangea gardens with Shonan coast views."},"에노시마":{"name":"Enoshima Island","desc":"Small island next to Kamakura with shrines, an observation tower, sea caves, and Mt. Fuji views."}}}},
"다카야마":{en:{description:"Takayama is a mountain town in Gifu called 'Little Kyoto' where Edo-era streets are preserved, famed for its festival and Hida beef.",spots:{"산마치스지":{"name":"Sanmachi-suji","desc":"Perfectly preserved Edo-era merchant district with traditional sake breweries and artisan shops."},"다카야마 진야":{"name":"Takayama Jinya","desc":"The only intact Edo-period government office building in Japan, once ruled directly by the shogunate."},"시라카와고":{"name":"Shirakawa-go","desc":"UNESCO World Heritage village of gassho-zukuri thatched farmhouses, world-famous for its winter snowscape."},"히다규 스테이크":{"name":"Hida Beef","desc":"One of Japan's top three wagyu beefs, available at specialty restaurants throughout Takayama."}}}},
